package com.example.mpos.inventory;
import android.content.Intent;import android.database.Cursor;import android.os.Bundle;import android.widget.*;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.database.DatabaseHelper;import java.util.*;
public class InventoryActivity extends AppCompatActivity{public void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_inventory);DatabaseHelper db=new DatabaseHelper(this);Cursor c=db.getReadableDatabase().rawQuery("SELECT name,stock_quantity,min_stock_quantity FROM products WHERE is_active=1 ORDER BY stock_quantity ASC",null);List<String>rows=new ArrayList<>();try{while(c.moveToNext()){int q=c.getInt(1),m=c.getInt(2);rows.add(c.getString(0)+"\nTồn: "+q+(q<=m?" • Tồn thấp":""));}}finally{c.close();}if(rows.isEmpty())rows.add("Chưa có sản phẩm tồn kho");((ListView)findViewById(R.id.listInventory)).setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_list_item_1,rows));findViewById(R.id.btnBack).setOnClickListener(v->finish());findViewById(R.id.btnStockAdjust).setOnClickListener(v->startActivity(new Intent(this,StockAdjustmentActivity.class)));findViewById(R.id.btnInventoryHistory).setOnClickListener(v->startActivity(new Intent(this,InventoryHistoryActivity.class)));}}
